router.get('/presets/:preset', async (req, res) => {
  const presetName = req.params.preset;

  // Validate preset name
  if (\!isValidPreset(presetName)) {
    return res.status(400).json({ error: 'Invalid preset name' });
  }

  try {
    const presetModels = getPresetModels(presetName as PresetName);
    res.json(presetModels);
  } catch (error) {
    res.status(500).json({ error: 'Failed to get preset models' });
  }
});

